# todo.py
from storage import save_todos, load_todos

def complete_todo(todo_list, index):
    """Marks the todo item at the given index as completed."""
    if index < 0 or index >= len(todo_list):
        raise IndexError("Index out of bounds")
    todo_list[index] = "✅ " + todo_list[index]

def save_todos(todo_list, filename="todos.json"):
    """Saves the todo list to a JSON file."""
    save_todos(todo_list, filename)

def load_todos(filename="todos.json"):
    """Loads the todo list from a JSON file."""
    return load_todos(filename)
